/**
 * Generate DEV.to firewall config.
 *
 * Data source: https://developers.forem.com/api/v0
 *
 * DEV.to (Forem) is a community platform for developers.
 * Uses custom "api-key" header (not Bearer).
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://developers.forem.com/api/v0";
// Token format: 24 alphanumeric chars [a-zA-Z0-9]
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSaf";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from DEV.to (Forem) API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:devto",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../contracts/firewalls";',
    "",
    "export const devtoFirewall = {",
    '  name: "devto",',
    '  description: "DEV.to API",',
    "  placeholders: {",
    `    DEVTO_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://dev.to/api",',
    "      auth: {",
    "        headers: {",
    '          "api-key": "${{ secrets.DEVTO_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating DEV.to firewall config...");
  const ts = generateTypeScript();
  writeOutput("devto", ts, import.meta.dirname);
}
